app = Flask(__name__)

memcache_client = Client(('localhost', 11211))


def json_serializer(key, value):
    if type(value) == str:
        return value.encode('utf-8'), 1
    return json.dumps(value).encode('utf-8'), 2


def json_deserializer(key, value, flags):
    if flags == 1:
        return value.decode('utf-8')
    if flags == 2:
        return json.loads(value.decode('utf-8'))
    return value


memcache_client.serializer = json_serializer
memcache_client.deserializer = json_deserializer


def cache_key_generator(*args, **kwargs):
    key_data = json.dumps({'args': args, 'kwargs': kwargs}, sort_keys=True)
    return hashlib.md5(key_data.encode()).hexdigest()


def cache_response(ttl=300, key_prefix=''):
    def decorator(f):
        @wraps(f)
        def wrapper(*args, **kwargs):
            cache_key = f"{key_prefix}:{f.__name__}:{cache_key_generator(*args, **kwargs)}"
            
            cached_data = memcache_client.get(cache_key)
            if cached_data is not None:
                return cached_data
            
            result = f(*args, **kwargs)
            memcache_client.set(cache_key, result, expire=ttl)
            return result
        return wrapper
    return decorator


