@app.route('/cache/invalidate', methods=['POST'])
def invalidate_cache_endpoint():
    cache_key = request.json.get('key')
    if cache_key:
        result = memcache_client.delete(cache_key)
        return jsonify({
            'message': 'Cache invalidated',
            'key': cache_key,
            'success': result
        })
    return jsonify({'error': 'No key provided'}), 400


@app.route('/cache/stats', methods=['GET'])
def get_cache_stats():
    stats = memcache_client.stats()
    return jsonify({
        'stats': stats
    })


@app.route('/cache/flush', methods=['POST'])
def flush_cache():
    memcache_client.flush_all()
    return jsonify({'message': 'All cache flushed'})


@app.route('/cache/set', methods=['POST'])
def set_cache():
    data = request.json
    key = data.get('key')
    value = data.get('value')
    ttl = data.get('ttl', 300)
    
    if key and value:
        memcache_client.set(key, value, expire=ttl)
        return jsonify({
            'message': 'Cache set successfully',
            'key': key,
            'ttl': ttl
        })
    return jsonify({'error': 'Key and value required'}), 400


@app.route('/cache/get/<key>', methods=['GET'])
def get_cache(key):
    value = memcache_client.get(key)
    if value is not None:
        return jsonify({
            'key': key,
            'value': value,
            'found': True
        })
    return jsonify({
        'key': key,
        'found': False
    }), 404


@app.route('/health', methods=['GET'])
def health_check():
    try:
        memcache_client.set('health_check', 'ok', expire=10)
        value = memcache_client.get('health_check')
        memcache_status = 'connected' if value == 'ok' else 'error'
    except Exception as e:
        memcache_status = f'error: {str(e)}'
    
    return jsonify({
        'status': 'healthy',
        'memcache': memcache_status
    })


